package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithRecordSeparator() {
        CSVFormat original = CSVFormat.DEFAULT;
        char separator = '\n';

        CSVFormat result = original.withRecordSeparator(separator);

        assertNotNull(result);
        assertNotSame(original, result);
        assertEquals(String.valueOf(separator), result.getRecordSeparator());

        // Test with different separator
        char sep2 = '\r';
        CSVFormat result2 = original.withRecordSeparator(sep2);
        assertEquals(String.valueOf(sep2), result2.getRecordSeparator());

        // Test with a non-line break character
        char sep3 = 'X';
        CSVFormat result3 = original.withRecordSeparator(sep3);
        assertEquals(String.valueOf(sep3), result3.getRecordSeparator());

        // Test with default record separator unchanged
        assertEquals(CSVFormat.DEFAULT.getRecordSeparator(), CSVFormat.DEFAULT.getRecordSeparator());
    }
}
